3126 // WARNING: keep in sync with SimplifyCFGOpt::simplifyUnreachable()!
3127 bool InstCombinerImpl::removeInstructionsBeforeUnreachable(Instruction &I) {
3128   // Try to remove the previous instruction if it must lead to unreachable.
3129   // This includes instructions like stores and "llvm.assume" that may not get
3130   // removed by simple dead code elimination.
3131   bool Changed = false;
3132   while (Instruction *Prev = I.getPrevNonDebugInstruction()) {
3133     // While we theoretically can erase EH, that would result in a block that
3134     // used to start with an EH no longer starting with EH, which is invalid.
3135     // To make it valid, we'd need to fixup predecessors to no longer refer to
3136     // this block, but that changes CFG, which is not allowed in InstCombine.
3137     if (Prev->isEHPad())
3138       break; // Can not drop any more instructions. We're done here.
3139 
3140     if (!isGuaranteedToTransferExecutionToSuccessor(Prev))
3141       break; // Can not drop any more instructions. We're done here.
3142     // Otherwise, this instruction can be freely erased,
3143     // even if it is not side-effect free.
3144 
3145     // A value may still have uses before we process it here (for example, in
3146     // another unreachable block), so convert those to poison.
3147     replaceInstUsesWith(*Prev, PoisonValue::get(Prev->getType()));
3148     eraseInstFromFunction(*Prev);
3149     Changed = true;
3150   }
3151   return Changed;
3152 }
