3234 void InstCombinerImpl::handlePotentiallyDeadBlocks(
3235     SmallVectorImpl<BasicBlock *> &Worklist) {
3236   while (!Worklist.empty()) {
3237     BasicBlock *BB = Worklist.pop_back_val();
3238     if (!all_of(predecessors(BB), [&](BasicBlock *Pred) {
3239           return DeadEdges.contains({Pred, BB}) || DT.dominates(BB, Pred);
3240         }))
3241       continue;
3242 
3243     handleUnreachableFrom(&BB->front(), Worklist);
3244   }
3245 }
