2072 /// If the inlined function had a higher stack protection level than the
2073 /// calling function, then bump up the caller's stack protection level.
2074 static void adjustCallerSSPLevel(Function &Caller, const Function &Callee) {
2075   // If the calling function has *no* stack protection level (e.g. it was built
2076   // with Clang's -fno-stack-protector or no_stack_protector attribute), don't
2077   // change it as that could change the program's semantics.
2078   if (!Caller.hasStackProtectorFnAttr())
2079     return;
2080 
2081   // If upgrading the SSP attribute, clear out the old SSP Attributes first.
2082   // Having multiple SSP attributes doesn't actually hurt, but it adds useless
2083   // clutter to the IR.
2084   AttributeMask OldSSPAttr;
2085   OldSSPAttr.addAttribute(Attribute::StackProtect)
2086       .addAttribute(Attribute::StackProtectStrong)
2087       .addAttribute(Attribute::StackProtectReq);
2088 
2089   if (Callee.hasFnAttribute(Attribute::StackProtectReq)) {
2090     Caller.removeFnAttrs(OldSSPAttr);
2091     Caller.addFnAttr(Attribute::StackProtectReq);
2092   } else if (Callee.hasFnAttribute(Attribute::StackProtectStrong) &&
2093              !Caller.hasFnAttribute(Attribute::StackProtectReq)) {
2094     Caller.removeFnAttrs(OldSSPAttr);
2095     Caller.addFnAttr(Attribute::StackProtectStrong);
2096   } else if (Callee.hasFnAttribute(Attribute::StackProtect) &&
2097              !Caller.hasFnAttribute(Attribute::StackProtectReq) &&
2098              !Caller.hasFnAttribute(Attribute::StackProtectStrong))
2099     Caller.addFnAttr(Attribute::StackProtect);
