1900 Value *InstCombinerImpl::SimplifyDemandedUseFPClass(
1901     Value *V, const FPClassTest DemandedMask, KnownFPClass &Known,
1902     unsigned Depth, Instruction *CxtI) {
1903   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
1904   Type *VTy = V->getType();
1905 
1906   assert(Known == KnownFPClass() && "expected uninitialized state");
1907 
1908   if (DemandedMask == fcNone)
1909     return isa<UndefValue>(V) ? nullptr : PoisonValue::get(VTy);
1910 
1911   if (Depth == MaxAnalysisRecursionDepth)
1912     return nullptr;
1913 
1914   Instruction *I = dyn_cast<Instruction>(V);
1915   if (!I) {
1916     // Handle constants and arguments
1917     Known = computeKnownFPClass(V, fcAllFlags, CxtI, Depth + 1);
1918     Value *FoldedToConst =
1919         getFPClassConstant(VTy, DemandedMask & Known.KnownFPClasses);
1920     return FoldedToConst == V ? nullptr : FoldedToConst;
1921   }
1922 
1923   if (!I->hasOneUse())
1924     return nullptr;
1925 
1926   // TODO: Should account for nofpclass/FastMathFlags on current instruction
1927   switch (I->getOpcode()) {
1928   case Instruction::FNeg: {
1929     if (SimplifyDemandedFPClass(I, 0, llvm::fneg(DemandedMask), Known,
1930                                 Depth + 1))
1931       return I;
1932     Known.fneg();
1933     break;
1934   }
1935   case Instruction::Call: {
1936     CallInst *CI = cast<CallInst>(I);
1937     switch (CI->getIntrinsicID()) {
1938     case Intrinsic::fabs:
1939       if (SimplifyDemandedFPClass(I, 0, llvm::inverse_fabs(DemandedMask), Known,
1940                                   Depth + 1))
1941         return I;
1942       Known.fabs();
1943       break;
1944     case Intrinsic::arithmetic_fence:
1945       if (SimplifyDemandedFPClass(I, 0, DemandedMask, Known, Depth + 1))
1946         return I;
1947       break;
1948     case Intrinsic::copysign: {
1949       // Flip on more potentially demanded classes
1950       const FPClassTest DemandedMaskAnySign = llvm::unknown_sign(DemandedMask);
1951       if (SimplifyDemandedFPClass(I, 0, DemandedMaskAnySign, Known, Depth + 1))
1952         return I;
1953 
1954       if ((DemandedMask & fcPositive) == fcNone) {
1955         // Roundabout way of replacing with fneg(fabs)
1956         I->setOperand(1, ConstantFP::get(VTy, -1.0));
1957         return I;
1958       }
1959 
1960       if ((DemandedMask & fcNegative) == fcNone) {
1961         // Roundabout way of replacing with fabs
1962         I->setOperand(1, ConstantFP::getZero(VTy));
1963         return I;
1964       }
1965 
1966       KnownFPClass KnownSign =
1967           computeKnownFPClass(I->getOperand(1), fcAllFlags, CxtI, Depth + 1);
1968       Known.copysign(KnownSign);
1969       break;
1970     }
1971     default:
1972       Known = computeKnownFPClass(I, ~DemandedMask, CxtI, Depth + 1);
1973       break;
1974     }
1975 
1976     break;
1977   }
1978   case Instruction::Select: {
1979     KnownFPClass KnownLHS, KnownRHS;
1980     if (SimplifyDemandedFPClass(I, 2, DemandedMask, KnownRHS, Depth + 1) ||
1981         SimplifyDemandedFPClass(I, 1, DemandedMask, KnownLHS, Depth + 1))
1982       return I;
1983 
1984     if (KnownLHS.isKnownNever(DemandedMask))
1985       return I->getOperand(2);
1986     if (KnownRHS.isKnownNever(DemandedMask))
1987       return I->getOperand(1);
1988 
1989     // TODO: Recognize clamping patterns
1990     Known = KnownLHS | KnownRHS;
1991     break;
1992   }
1993   default:
1994     Known = computeKnownFPClass(I, ~DemandedMask, CxtI, Depth + 1);
1995     break;
1996   }
1997 
1998   return getFPClassConstant(VTy, DemandedMask & Known.KnownFPClasses);
1999 }
